// Safely get paper metadata from earlier in the chain
const paperData = $item(0).$node['Parse Papers'].json || {};
const url = paperData.url || 'n/a';
const content = String($json.body || $json.data || $json.content || '').slice(0, 12000);

if (!content || content.length < 100) {
  return [{ json: { ...paperData, ok: false, error_type: 'fetch_failed', error_message: 'Content too short' } }];
}

const payload = {
  model: 'solar-pro2',
  temperature: 0.2,
  response_format: {
    type: 'json_schema',
    json_schema: {
      name: 'deep_analysis',
      schema: {
        type: 'object',
        properties: {
          title: { type: 'string' },
          one_line: { type: 'string' },
          problem: { type: 'string' },
          method: { type: 'string' },
          results: { type: 'string' },
          limitations: { type: 'string' },
          novelty: { type: 'string' },
          impact: { type: 'string' },
          related_work_gaps: { type: 'string' },
          tags: { type: 'array', items: { type: 'string' } },
          action_items: { type: 'array', items: { type: 'string' } },
          search_queries: { type: 'array', items: { type: 'string' } }
        },
        required: ['title','one_line','problem','method','results','limitations','novelty','impact','related_work_gaps','tags','action_items','search_queries'],
        additionalProperties: false
      }
    }
  },
  messages: [
    { role: 'system', content: '너는 시니어 연구자다. ko로 답하라. 과장 금지. 수치/실험 조건 보존. novelty(새로운 점), impact(실무적 영향), related_work_gaps(선행연구 대비 빈 곳)를 반드시 분석하라. search_queries에는 관련 논문을 더 찾기 위한 검색어 3개를 영어로 제안하라.' },
    { role: 'user', content: '다음 논문을 깊이 분석하라.\nURL: ' + url + '\n\n본문:\n' + content }
  ]
};

return [{ json: { ...paperData, upstage_payload: payload } }];

// Get original paper data from Build Analysis Payload (before HTTP)
const paperData = $item(0).$node['Build Analysis Payload'].json || {};
const base = {
  paper_id: paperData.paper_id || '',
  title: paperData.title || '',
  url: paperData.url || '',
  upvotes: paperData.upvotes || 0,
  date: paperData.date || ''
};

if ($json.error || (!$json.choices && !$json.body?.choices)) {
  return [{ json: { ...base, ok: false, error_type: 'upstage_error', error_message: $json.error?.message || $json.message || 'Unknown' } }];
}

const choices = $json.choices || $json.body?.choices || [];
const content = choices?.[0]?.message?.content || '{}';
let parsed;
try { parsed = JSON.parse(content); } catch { parsed = { raw: content }; }
return [{ json: { ...base, ok: true, analysis: parsed } }];

// Aggregate all paper analyses and build synthesis prompt
const all = $input.all().map(i => i.json);
const ok = all.filter(x => x.ok !== false);
const failed = all.filter(x => x.ok === false);
const date = all[0]?.date || 'unknown';

// Collect search queries and tags
const allQueries = ok.flatMap(x => x.analysis?.search_queries || []);
const uniqueQueries = [...new Set(allQueries)].slice(0, 8);
const allTags = ok.flatMap(x => x.analysis?.tags || []);
const tagCount = {};
allTags.forEach(t => { tagCount[t] = (tagCount[t]||0) + 1; });
const topTags = Object.entries(tagCount).sort((a,b)=>b[1]-a[1]).slice(0,8).map(x=>x[0]);

// Build synthesis prompt
const papersText = ok.map((x,i) => {
  const a = x.analysis || {};
  return `${i+1}. ${a.title || x.title}\n한줄: ${a.one_line || '-'}\nnovelty: ${a.novelty || '-'}\nimpact: ${a.impact || '-'}\ngaps: ${a.related_work_gaps || '-'}`;
}).join('\n\n');

const synthPayload = {
  model: 'solar-pro2',
  temperature: 0.3,
  response_format: {
    type: 'json_schema',
    json_schema: {
      name: 'trend_synthesis',
      schema: {
        type: 'object',
        properties: {
          trend_summary: { type: 'string' },
          key_themes: { type: 'array', items: { type: 'string' } },
          opportunities: { type: 'array', items: { type: 'string' } },
          risks: { type: 'array', items: { type: 'string' } },
          recommended_reading: { type: 'array', items: { type: 'string' } }
        },
        required: ['trend_summary','key_themes','opportunities','risks','recommended_reading'],
        additionalProperties: false
      }
    }
  },
  messages: [
    { role: 'system', content: '너는 연구 트렌드 분석가다. 오늘의 인기 논문들을 종합해 큰 그림을 그려라. ko로 답하라.' },
    { role: 'user', content: `오늘 HF Daily Papers Top ${ok.length} 분석 결과:\n${papersText}\n\n위 논문들의 공통 트렌드, 기회, 리스크를 종합 분석하고, 추가로 읽어볼 만한 방향을 추천해라.` }
  ]
};

// IMPORTANT: Pack ALL data needed for email into this output
// because after the HTTP node, only $json from HTTP response will be available
// We use _meta to carry forward papers data
return [{ json: {
  synth_payload: synthPayload,
  _meta: JSON.stringify({ date, papers: ok, failed_count: failed.length, top_tags: topTags, search_queries: uniqueQueries })
} }];

// Recover papers data from Collect node (stored as _meta string)
const collectOutput = $item(0).$node['Collect & Build Synthesis'].json || {};
let meta;
try {
  meta = JSON.parse(collectOutput._meta || '{}');
} catch {
  meta = { date: 'unknown', papers: [], failed_count: 0, top_tags: [], search_queries: [] };
}

const { date, papers, failed_count, top_tags: topTags, search_queries: searchQueries } = meta;

// Parse synthesis response
let synth = {};
try {
  const raw = $json.choices?.[0]?.message?.content || $json.body?.choices?.[0]?.message?.content || '{}';
  synth = JSON.parse(raw);
} catch { synth = { trend_summary: '트렌드 종합 파싱 실패' }; }

// Build HTML email
let html = `<div style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif;max-width:700px;margin:0 auto;padding:24px;">`;
html += `<h1 style="font-size:22px;color:#1a1a1a;">🧠 Research Briefing — ${date}</h1>`;
html += `<p style="color:#6b7280;font-size:14px;">Top ${papers.length} 논문 심층 분석 + 트렌드 종합</p>`;

// Trend synthesis box
html += `<div style="background:#f3eeff;border-radius:12px;padding:18px;margin:20px 0;">`;
html += `<h2 style="font-size:16px;color:#6c2bd9;margin:0 0 10px;">📊 오늘의 트렌드</h2>`;
html += `<p style="font-size:14px;color:#374151;margin:0 0 12px;">${synth.trend_summary || '-'}</p>`;
if (synth.key_themes?.length) html += `<p style="font-size:13px;color:#4b5563;"><strong>핵심 테마:</strong> ${synth.key_themes.join(' · ')}</p>`;
if (synth.opportunities?.length) html += `<p style="font-size:13px;color:#059669;margin-top:6px;"><strong>🟢 기회:</strong> ${synth.opportunities.join(' · ')}</p>`;
if (synth.risks?.length) html += `<p style="font-size:13px;color:#ef4444;margin-top:6px;"><strong>🔴 리스크:</strong> ${synth.risks.join(' · ')}</p>`;
if (synth.recommended_reading?.length) html += `<p style="font-size:13px;color:#6b7280;margin-top:6px;"><strong>📚 추가 읽기:</strong> ${synth.recommended_reading.join(' · ')}</p>`;
html += `</div>`;

// Individual papers
html += `<hr style="border:none;border-top:1px solid #e5e7eb;margin:20px 0;">`;
for (const item of papers) {
  const a = item.analysis || {};
  html += `<div style="margin-bottom:24px;">`;
  html += `<h3 style="font-size:15px;margin:0 0 6px;"><a href="${item.url || '#'}" style="color:#6c2bd9;text-decoration:none;">${a.title || item.title || 'Untitled'}</a></h3>`;
  html += `<p style="color:#6b7280;font-size:12px;margin:0 0 6px;">⬆️ ${item.upvotes || 0} · ${(a.tags||[]).join(', ')}</p>`;
  html += `<p style="font-size:13px;color:#374151;"><strong>한 줄:</strong> ${a.one_line || '-'}</p>`;
  html += `<table style="font-size:12px;color:#4b5563;border-collapse:collapse;width:100%;margin-top:6px;">`;
  html += `<tr><td style="padding:2px 6px 2px 0;font-weight:600;vertical-align:top;">문제</td><td>${a.problem||'-'}</td></tr>`;
  html += `<tr><td style="padding:2px 6px 2px 0;font-weight:600;vertical-align:top;">방법</td><td>${a.method||'-'}</td></tr>`;
  html += `<tr><td style="padding:2px 6px 2px 0;font-weight:600;vertical-align:top;">결과</td><td>${a.results||'-'}</td></tr>`;
  html += `<tr><td style="padding:2px 6px 2px 0;font-weight:600;vertical-align:top;">새로운 점</td><td>${a.novelty||'-'}</td></tr>`;
  html += `<tr><td style="padding:2px 6px 2px 0;font-weight:600;vertical-align:top;">영향</td><td>${a.impact||'-'}</td></tr>`;
  html += `<tr><td style="padding:2px 6px 2px 0;font-weight:600;vertical-align:top;">빈 곳</td><td>${a.related_work_gaps||'-'}</td></tr>`;
  html += `</table>`;
  if (a.action_items?.length) html += `<p style="font-size:11px;color:#059669;margin-top:4px;">💡 ${a.action_items.join(' · ')}</p>`;
  html += `</div>`;
}

// Search queries
if (searchQueries?.length) {
  html += `<div style="background:#f9fafb;border-radius:10px;padding:14px;margin:16px 0;">`;
  html += `<p style="font-size:13px;color:#374151;margin:0;"><strong>🔍 관련 논문 탐색:</strong></p>`;
  html += `<p style="font-size:12px;color:#6b7280;margin:4px 0 0;">${searchQueries.map(q => `<a href="https://scholar.google.com/scholar?q=${encodeURIComponent(q)}" style="color:#6c2bd9;">${q}</a>`).join(' · ')}</p>`;
  html += `</div>`;
}

if (failed_count > 0) html += `<p style="color:#ef4444;font-size:12px;">⚠️ ${failed_count}편 분석 실패</p>`;
html += `<hr style="border:none;border-top:1px solid #e5e7eb;margin:20px 0;">`;
html += `<p style="color:#9ca3af;font-size:12px;">Powered by <a href="https://www.upstage.ai" style="color:#6c2bd9;">Upstage Solar</a> · <a href="https://huggingface.co/papers" style="color:#6c2bd9;">HF Daily Papers</a></p></div>`;

return [{ json: {
  date,
  subject: `🧠 Research Briefing — ${date} (${papers.length}편 분석)`,
  html,
  paper_count: papers.length,
  top_tags: topTags
} }];

const dateStr = new Date(Date.now() - 86400000).toISOString().slice(0,10);
let papers = [];

// Handle all possible n8n HTTP response formats
const raw = $input.first().json;
try {
  if (Array.isArray(raw)) papers = raw;
  else if (Array.isArray(raw?.body)) papers = raw.body;
  else if (typeof raw === 'string') papers = JSON.parse(raw);
  else if (typeof raw?.body === 'string' && raw.body.trim().startsWith('[')) papers = JSON.parse(raw.body);
  else {
    // n8n may auto-parse the JSON array into numbered keys
    const keys = Object.keys(raw).filter(k => !isNaN(k));
    if (keys.length > 0) {
      papers = keys.map(k => raw[k]);
    }
  }
} catch (e) {}

if (!papers.length) {
  return [{ json: { date: dateStr, paper_id: 'none', title: 'No papers found for ' + dateStr, url: '#', upvotes: 0 } }];
}

papers.sort((a,b) => (b.paper?.upvotes||0) - (a.paper?.upvotes||0));
return papers.slice(0, 5).map(p => ({
  json: {
    date: dateStr,
    paper_id: p.paper?.id || '',
    title: p.paper?.title || 'Untitled',
    url: 'https://huggingface.co/papers/' + (p.paper?.id || ''),
    upvotes: p.paper?.upvotes || 0
  }
}));
